import{_ as a,o as r,c as t,ah as d}from"./chunks/framework.BNo2o5Ln.js";const k=JSON.parse('{"title":"分布式锁","description":"","frontmatter":{"title":"分布式锁","order":4},"headers":[],"relativePath":"server/distribute/basic/lock.md","filePath":"server/distribute/basic/lock.md"}'),i={name:"server/distribute/basic/lock.md"};function l(o,e,p,h,n,s){return r(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="分布式锁" tabindex="-1">分布式锁 <a class="header-anchor" href="#分布式锁" aria-label="Permalink to “分布式锁”">​</a></h1><p>分布式锁是在分布式环境中实现互斥访问的机制，用于控制多个进程对共享资源的访问。分布式锁是分布式系统的基础组件，广泛应用于任务调度、库存扣减、幂等性保证。</p><h2 id="为什么需要分布式锁" tabindex="-1">为什么需要分布式锁 <a class="header-anchor" href="#为什么需要分布式锁" aria-label="Permalink to “为什么需要分布式锁”">​</a></h2><p>单机锁（如 Java 的 synchronized、ReentrantLock）只能在单机进程内有效，无法跨进程、跨机器。分布式系统需要分布式锁来协调多个进程的访问。</p><p>分布式锁的应用场景：任务调度（只有一个节点执行定时任务）、库存扣减（防止超卖）、幂等性保证（防止重复提交）、资源访问（控制并发访问量）。</p><h2 id="分布式锁的设计要求" tabindex="-1">分布式锁的设计要求 <a class="header-anchor" href="#分布式锁的设计要求" aria-label="Permalink to “分布式锁的设计要求”">​</a></h2><p>互斥性：同一时刻只有一个进程能获得锁。</p><p>容错性：锁服务故障时，仍能正常工作。锁服务需要集群部署，避免单点故障。</p><p>避免死锁：持有锁的进程崩溃，锁能够自动释放。需要设置超时时间或心跳续约。</p><p>可重入性：同一个进程可以多次获得同一个锁。需要记录锁的持有者。</p><p>高性能：获得锁和释放锁的操作要快。锁服务的性能要足够高。</p><h2 id="基于-redis-的分布式锁" tabindex="-1">基于 Redis 的分布式锁 <a class="header-anchor" href="#基于-redis-的分布式锁" aria-label="Permalink to “基于 Redis 的分布式锁”">​</a></h2><h3 id="set-nx-ex" tabindex="-1">SET NX EX <a class="header-anchor" href="#set-nx-ex" aria-label="Permalink to “SET NX EX”">​</a></h3><p>SET key value NX EX 命令可以设置一个带过期时间的 key，如果 key 不存在则设置成功，返回 OK，表示获得锁。如果 key 已存在则设置失败，返回 nil，表示锁已被占用。</p><p>释放锁时删除 key，但需要判断 key 的值是否是自己设置的，避免误删其他进程的锁。使用 Lua 脚本保证原子性：if redis.call(&quot;get&quot;, KEYS[1]) == ARGV[1] then return redis.call(&quot;del&quot;, KEYS[1]) else return 0 end。</p><h3 id="set-nx-ex-的问题" tabindex="-1">SET NX EX 的问题 <a class="header-anchor" href="#set-nx-ex-的问题" aria-label="Permalink to “SET NX EX 的问题”">​</a></h3><p>锁超时：如果业务执行时间超过锁超时时间，锁会自动释放，其他进程可以获得锁，导致多个进程同时持有锁。解决方案：设置合理的超时时间，或使用 watchdog 续约。</p><p>主从切换：Redis 主从异步复制，Master 持有锁后未同步到 Slave 就故障，Slave 升级为 Master 后，其他进程可以获得锁，导致多个进程同时持有锁。解决方案：使用 Redlock 算法。</p><p>单点故障：Redis 单点故障会导致锁服务不可用。解决方案：使用 Redis Sentinel 或 Redis Cluster。</p><h3 id="redlock-算法" tabindex="-1">Redlock 算法 <a class="header-anchor" href="#redlock-算法" aria-label="Permalink to “Redlock 算法”">​</a></h3><p>Redlock 是 Redis 作者提出的分布式锁算法，使用多个独立的 Redis 实例（通常 5 个）。客户端依次获取所有实例的锁，如果多数实例获取成功，且获取时间小于锁超时时间，则认为获得锁。</p><p>释放锁时依次释放所有实例的锁。</p><p>Redlock 的问题：时钟跳跃问题，如果 Redis 服务器时钟回拨，可能导致锁提前过期。Redlock 的性能较差，需要与多个实例通信。</p><h2 id="基于-zookeeper-的分布式锁" tabindex="-1">基于 ZooKeeper 的分布式锁 <a class="header-anchor" href="#基于-zookeeper-的分布式锁" aria-label="Permalink to “基于 ZooKeeper 的分布式锁”">​</a></h2><h3 id="临时顺序节点" tabindex="-1">临时顺序节点 <a class="header-anchor" href="#临时顺序节点" aria-label="Permalink to “临时顺序节点”">​</a></h3><p>ZooKeeper 的临时节点会在客户端断开连接时自动删除，顺序节点保证节点名的有序性。分布式锁的实现：客户端创建临时顺序节点，如果序号最小，则获得锁。否则监听前一个节点的删除事件，当前一个节点删除时，尝试获得锁。</p><p>释放锁时删除节点，后一个节点会被通知，尝试获得锁。</p><h3 id="zookeeper-锁的优势" tabindex="-1">ZooKeeper 锁的优势 <a class="header-anchor" href="#zookeeper-锁的优势" aria-label="Permalink to “ZooKeeper 锁的优势”">​</a></h3><p>容错性：ZooKeeper 集群通过 ZAB 协议保证一致性，即使部分节点故障，仍能正常工作。</p><p>避免死锁：临时节点会在客户端断开连接时自动删除，即使客户端崩溃，锁也能释放。</p><p>可重入性：可以在节点数据中记录锁的持有者和重入次数，实现可重入锁。</p><p>公平锁：临时顺序节点保证先来先得，实现公平锁。</p><h3 id="zookeeper-锁的问题" tabindex="-1">ZooKeeper 锁的问题 <a class="header-anchor" href="#zookeeper-锁的问题" aria-label="Permalink to “ZooKeeper 锁的问题”">​</a></h3><p>性能：ZooKeeper 的写操作需要同步到多数节点，性能较低。创建和删除节点的开销较大。</p><p>复杂性：需要监听节点事件，处理连接断开重连，实现较复杂。</p><h2 id="基于数据库的分布式锁" tabindex="-1">基于数据库的分布式锁 <a class="header-anchor" href="#基于数据库的分布式锁" aria-label="Permalink to “基于数据库的分布式锁”">​</a></h2><h3 id="悲观锁" tabindex="-1">悲观锁 <a class="header-anchor" href="#悲观锁" aria-label="Permalink to “悲观锁”">​</a></h3><p>SELECT FOR UPDATE 语句可以对行加排他锁，其他事务无法修改该行。获得锁：开启事务，执行 SELECT FOR UPDATE，提交事务时释放锁。</p><p>悲观锁的问题：数据库压力大，锁表或死锁风险。</p><h3 id="乐观锁" tabindex="-1">乐观锁 <a class="header-anchor" href="#乐观锁" aria-label="Permalink to “乐观锁”">​</a></h3><p>乐观锁通过版本号实现，更新时检查版本号是否变化。UPDATE table SET value = 1, version = version + 1 WHERE id = 1 AND version = 5。如果更新成功，则获得锁。如果更新失败，则版本号已变化，锁已被占用。</p><p>乐观锁的问题：并发高时冲突多，需要重试。</p><h3 id="唯一索引" tabindex="-1">唯一索引 <a class="header-anchor" href="#唯一索引" aria-label="Permalink to “唯一索引”">​</a></h3><p>唯一索引可以保证只有一个插入成功。INSERT INTO lock (lock_name) VALUES (&#39;my_lock&#39;) ON DUPLICATE KEY UPDATE。如果插入成功，则获得锁。如果插入失败（唯一索引冲突），则锁已被占用。</p><p>释放锁时删除记录。需要设置过期时间，避免死锁。</p><h2 id="分布式锁的对比" tabindex="-1">分布式锁的对比 <a class="header-anchor" href="#分布式锁的对比" aria-label="Permalink to “分布式锁的对比”">​</a></h2><table tabindex="0"><thead><tr><th>实现方式</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>Redis SET NX EX</td><td>性能高、实现简单</td><td>主从切换时可能失效</td></tr><tr><td>Redis Redlock</td><td>容错性好</td><td>性能差、时钟问题</td></tr><tr><td>ZooKeeper</td><td>容错性好、避免死锁</td><td>性能较差、实现复杂</td></tr><tr><td>数据库悲观锁</td><td>实现简单</td><td>性能差、锁表风险</td></tr><tr><td>数据库乐观锁</td><td>无锁阻塞</td><td>并发高时冲突多</td></tr></tbody></table><h2 id="分布式锁的最佳实践" tabindex="-1">分布式锁的最佳实践 <a class="header-anchor" href="#分布式锁的最佳实践" aria-label="Permalink to “分布式锁的最佳实践”">​</a></h2><p>设置合理的超时时间：超时时间要大于业务执行时间，但也不能太大，否则死锁时间过长。</p><p>使用心跳续约：如果业务执行时间不确定，可以使用 watchdog 线程定期续约，延长锁超时时间。</p><p>处理异常：业务代码要捕获异常，确保 finally 块中释放锁。</p><p>使用 Lua 脚本：Redis 的获取和释放操作要使用 Lua 脚本，保证原子性。</p><p>记录锁信息：锁的 value 可以记录客户端标识，便于排查问题。</p><p>监控锁持有时间：如果锁持有时间过长，可能是业务问题或死锁。</p><h2 id="分布式锁的替代方案" tabindex="-1">分布式锁的替代方案 <a class="header-anchor" href="#分布式锁的替代方案" aria-label="Permalink to “分布式锁的替代方案”">​</a></h2><p>串行化：将任务放入队列，由单个消费者依次执行。可以避免锁，但性能受限于单个消费者。</p><p>幂等性：设计幂等的业务逻辑，即使重复执行也不会出错。可以避免锁，但需要业务配合。</p><p>分段锁：将锁分段，减少锁冲突。例如库存扣减，可以按商品 ID 分段，不同商品可以并发扣减。</p><p>分布式锁是分布式系统的基础组件，理解分布式锁的原理和实现，有助于设计合适的并发控制方案。</p>',59)])])}const b=a(i,[["render",l]]);export{k as __pageData,b as default};
